SELECT * FROM t_repair_plant


        and enterprise_id = #{query.enterpriseId}


        and deleted_flag = #{query.deletedFlag}


        AND disabled_flag = #{query.disabledFlag}


        AND ( INSTR(repair_plant_name,#{query.searchWord})
            OR INSTR(contact_name,#{query.searchWord})
            OR INSTR(contact_phone,#{query.searchWord})
            OR INSTR(address_area,#{query.searchWord})
            OR INSTR(create_user_name,#{query.searchWord})
        )


        AND DATE_FORMAT(create_time, '%Y-%m-%d') >= DATE_FORMAT(#{query.startDate}, '%Y-%m-%d')


        AND DATE_FORMAT(create_time, '%Y-%m-%d') <= DATE_FORMAT(#{query.endDate}, '%Y-%m-%d')



    ORDER BY repair_plant_id DESC

SELECT * FROM t_repair_plant
WHERE enterprise_id = #{enterpriseId} and deleted_flag = #{deletedFlag} AND repair_plant_name = #{repairPlantName}
LIMIT 1
